const raw = $input.first().json;

// sessionId comes from parent workflow via workflowInputs mapping
const sessionId = raw.sessionId || '';

// Parse query from LLM
let input;
try { input = JSON.parse(raw.query || raw.input || '{}'); } catch(e) { input = { content: raw.query }; }
const content = input.content || raw.query || raw.input || '';
const scope = input.scope || 'user';

// Determine user_id: org-scope = null, user-scope = sessionId from parent
let userId = null;
if (scope !== 'org') {
  userId = sessionId || null;
}

// Enriched memory fields (optional)
const tags = Array.isArray(input.tags) ? input.tags : null;
const entityName = input.entity_name || input.entity || null;
const sourceRef = input.source || 'agent';

// Generate embedding
async function getEmbedding(text) {
  const cfgResp = await helpers.httpRequest({ method: 'GET', url: '{{SUPABASE_URL}}/rest/v1/tools_config?tool_name=eq.embedding&select=config,enabled', headers: { 'apikey': '{{SUPABASE_SERVICE_KEY}}', 'Content-Type': 'application/json' } });
  const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0 && cfgResp[0].enabled) ? cfgResp[0].config : null;
  if (!cfg || !cfg.api_key) return null;
  const provider = cfg.provider || 'openai';
  const apiKey = cfg.api_key;
  const model = cfg.model || 'text-embedding-3-small';
  try {
    if (provider === 'openai') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.openai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model, input: text }) });
      return res.data[0].embedding;
    }
    if (provider === 'voyage') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.voyageai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'voyage-3-lite', input: [text] }) });
      return res.data[0].embedding;
    }
    if (provider === 'ollama') {
      const ollamaUrl = cfg.ollama_url || 'http://localhost:11434';
      const res = await helpers.httpRequest({ method: 'POST', url: `${ollamaUrl}/api/embed`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'nomic-embed-text', input: text }) });
      return res.embeddings[0];
    }
  } catch(e) { return null; }
  return null;
}

const embedding = await getEmbedding(content);
const body = {
  content,
  category: input.category || 'general',
  importance: input.importance || 5,
  user_id: userId,
  metadata: { source: 'agent', scope }
};
if (tags && tags.length > 0) body.tags = tags;
if (entityName) body.entity_name = entityName;
if (sourceRef) body.source = sourceRef;
if (embedding) body.embedding = JSON.stringify(embedding);

const result = await helpers.httpRequest({
  method: 'POST',
  url: '{{SUPABASE_URL}}/rest/v1/memory_long',
  headers: {
    'apikey': '{{SUPABASE_SERVICE_KEY}}',
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: JSON.stringify(body)
});

return [{ json: { success: true, saved: content, scope, user_id: userId, vectorized: !!embedding, tags: tags || [], entity_name: entityName || null } }];
